import type { NordicCoreContext } from '../../common/types';

import { getContext } from '../storage';

export function getSerializableContext(staticMarkup?: boolean) {
  const context = getContext();

  const result: NordicCoreContext = {
    deviceType: context.deviceType,
    platformType: context.platformType,
    platform: context.platform,
    webviewInfo: context.webviewInfo,
    deviceInfo: context.deviceInfo,
    networkState: context.networkState,
    safeAreaInsets: context.safeAreaInsets,
  };

  if (staticMarkup) {
    return result;
  }

  result.i18n = context.i18n;

  return result;
}
